#include &lt;unistd.h&gt;
#include &lt;stdlib.h&gt;
#include &lt;stdio.h&gt;

void daemonize_server() {
    // Engineer attempts to detach from the terminal BEFORE forking.
    if (setsid() == -1) {
        perror("Failed to create new session");
    }

    pid_t pid = fork();
    if (pid > 0) {
        exit(0); // Parent exits
    }

    // Child continues running as daemon...
}

#include &lt;stdio.h&gt;
#include &lt;stdlib.h&gt;
#include &lt;unistd.h&gt;
#include &lt;sys/types.h&gt;
#include &lt;sys/stat.h&gt;
#include &lt;fcntl.h&gt;
#include &lt;syslog.h&gt;

void skeleton_daemon() {
    pid_t pid;

    // 1. Fork off the parent process
    pid = fork();
    if (pid < 0) exit(EXIT_FAILURE);
    if (pid > 0) exit(EXIT_SUCCESS); // Parent exits instantly

    // 2. The Child becomes Session Leader to detach from terminal
    if (setsid() < 0) exit(EXIT_FAILURE);

    // 3. Catch, ignore and handle signals (Ignore SIGHUP)
    // (Optional, but recommended for robust daemons)

    // 4. Fork again to guarantee we are not a Session Leader
    pid = fork();
    if (pid < 0) exit(EXIT_FAILURE);
    if (pid > 0) exit(EXIT_SUCCESS); // Child 1 exits instantly

    // 5. Unmask file mode (Clear inherited umask)
    umask(0);

    // 6. Change working directory to root (Prevent locking up mounted USB drives)
    if ((chdir("/")) < 0) exit(EXIT_FAILURE);

    // 7. Close ALL open file descriptors inherited from Parent
    int max_fd = sysconf(_SC_OPEN_MAX);
    for (int i = 0; i < max_fd; i++) {
        close(i);
    }

    // 8. Re-open Standard I/O to /dev/null
    // Because 0,1,2 were just closed, the first open() is guaranteed to be FD 0.
    int fd0 = open("/dev/null", O_RDWR);
    int fd1 = dup(0); // Duplicates FD 0 into FD 1
    int fd2 = dup(0); // Duplicates FD 0 into FD 2
}

int main() {
    skeleton_daemon();

    // We are now a ghost. We have no terminal.
    // We must communicate via Syslog.
    openlog("my_custom_daemon", LOG_PID, LOG_DAEMON);
    syslog(LOG_NOTICE, "Daemon successfully booted.");

    // The infinite background heartbeat loop
    while (1) {
        syslog(LOG_NOTICE, "Heartbeat: System is stable.");
        sleep(10);
    }

    closelog();
    return EXIT_SUCCESS;
}
